strokes:
1px solid
      var(
        --supplier-editor-border-strong,
        color-mix(in oklab, rgb(var(--border-strong)) 72%, transparent)
      )

1px solid
          var(
            --ss-hybrid-divider,
            var(--ss-hybrid-border, color-mix(in oklab, rgb(var(--border-strong)) 40%, transparent))
          )

color-mix(
      in oklab,
      var(
          --supplier-editor-border-strong,
          color-mix(in oklab, rgb(var(--border-strong)) 72%, transparent)
        )
        84%,
      rgb(var(--fg)) 16%
    )

color-mix(
      in oklab,
      var(--supplier-editor-border, rgb(var(--border-strong))) 78%,
      rgb(var(--fg)) 22%
    )

color-mix(
      in oklab,
      var(--supplier-editor-border, rgb(var(--border-strong))) 84%,
      transparent
    )

color-mix(
      in oklab,
      var(--tp-pill-fg, var(--app-color-grid-pill-text)) 22%,
      transparent
    )

color-mix(
    in oklab,
    var(--app-color-outline) var(--app-outline-soft-mix),
    transparent
  )

color-mix(
    in oklab,
    var(--app-color-outline) var(--app-outline-stroke-mix),
    transparent
  )

color-mix(
    in oklab,
    var(--app-color-outline-stroke) var(--app-outline-empty-mix),
    transparent
  )

color-mix(
    in oklab,
    var(--brand-border, var(--dg-clickup-pill-tone-border)) 46%,
    var(--dg-clickup-pill-tone-border)
  )

color-mix(
    in oklab,
    var(--tone, var(--dg-pill-tone-teal)) 46%,
    var(--dg-clickup-pill-tone-border)
  )
